// → Descargar reporte Diag (PDF o HTML fallback)
const render = $('🖥️ Render HTML Diagnóstico').first().json;
const html = render.html || '';
const consolidar = $('📦 Consolidar Diagnóstico').first().json;
const nombreProyecto = consolidar.nombre || '';

function htmlItem(extra = {}) {
  const safeName = (nombreProyecto || 'proyecto')
    .replace(/[^\w\dáéíóúñÁÉÍÓÚÑ\s-]/gi, '').trim().slice(0, 40).replace(/\s+/g, '-');
  const slug = safeName || 'diagnostico';
  const fileName = `ZENTI-diagnostico-${slug}.html`;
  const buf = Buffer.from(html, 'utf8');
  return [{ json: { mensaje: 'Descarga: ' + fileName, nombre_proyecto: nombreProyecto, formato_entrega: 'html', ...extra }, binary: { data: { data: buf.toString('base64'), mimeType: 'text/html', fileExtension: 'html', fileName } } }];
}

const item = $input.first();
const bin = item.binary?.data;
let buf = null;
try { if (bin?.data) { buf = Buffer.from(bin.data, 'base64'); } } catch (e) { buf = null; }

const looksPdf = buf && buf.length >= 200 && (bin.mimeType?.includes('pdf') || bin.fileExtension === 'pdf' || buf.slice(0, 4).toString() === '%PDF');

if (looksPdf) {
  return [{ json: { mensaje: 'Descarga: ZENTI-diagnostico.pdf', nombre_proyecto: nombreProyecto, formato_entrega: 'pdf' }, binary: { data: { data: buf.toString('base64'), mimeType: 'application/pdf', fileExtension: 'pdf', fileName: 'ZENTI-diagnostico.pdf' } } }];
}

if (!html) { throw new Error('No hay HTML del reporte. Revisa 🖥️ Render HTML Diagnóstico y la cadena PDFShift.'); }

const errMsg = item.json?.error?.message || item.json?.error?.description || item.json?.error || item.json?.message || '';
const fallback = htmlItem(errMsg ? { mensaje: 'HTML (PDFShift falló)', pdf_error: String(errMsg).slice(0, 500) } : { mensaje: 'HTML (sin PDF de PDFShift)' });
fallback[0].json.formato_entrega = 'html';
return fallback;
